import React, { useState } from 'react';

const Header: React.FC = () => {
  const [showNotifications, setShowNotifications] = useState(false);
  const currentDate = new Date().toLocaleDateString('pt-AO', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const notifications = [
    { id: 1, title: 'Processamento Concluído', message: 'O salário de Março/2026 foi processado com sucesso.', time: '2 horas atrás', read: false },
    { id: 2, title: 'Novo Colaborador', message: 'Um novo colaborador foi adicionado ao sistema.', time: '1 dia atrás', read: true },
    { id: 3, title: 'Guia de IRS Pendente', message: 'A guia de IRS do mês Fevereiro está pendente de pagamento.', time: '2 dias atrás', read: true },
  ];

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <header className="h-16 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-background-dark/80 backdrop-blur-md sticky top-0 z-10 px-8 flex items-center justify-between">
      <div className="flex items-center gap-4 flex-1">
        <div className="max-w-md w-full relative">
          <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">search</span>
          <input
            className="w-full pl-10 pr-4 py-2 bg-slate-100 dark:bg-slate-800 border-none rounded-lg focus:ring-2 focus:ring-primary text-sm"
            placeholder="Pesquisar..."
            type="text"
          />
        </div>
      </div>
      <div className="flex items-center gap-4">
        <div className="relative">
          <button 
            onClick={() => setShowNotifications(!showNotifications)}
            className="p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg relative transition-colors"
          >
            <span className="material-symbols-outlined">notifications</span>
            {unreadCount > 0 && (
              <span className="absolute top-2 right-2 size-2 bg-red-500 rounded-full border-2 border-white dark:border-background-dark"></span>
            )}
          </button>
          {showNotifications && (
            <div className="absolute right-0 top-full mt-2 w-80 bg-white dark:bg-slate-900 rounded-xl shadow-xl border border-slate-200 dark:border-slate-800 overflow-hidden">
              <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between">
                <h3 className="font-bold text-slate-800 dark:text-white">Notificações</h3>
                <span className="text-xs text-slate-500">{unreadCount} não lidas</span>
              </div>
              <div className="max-h-80 overflow-y-auto">
                {notifications.map(notif => (
                  <div key={notif.id} className={`p-4 border-b border-slate-100 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer ${!notif.read ? 'bg-primary/5 dark:bg-primary/10' : ''}`}>
                    <div className="flex items-start gap-3">
                      <div className={`mt-1 size-2 rounded-full ${notif.read ? 'bg-slate-300' : 'bg-primary'}`}></div>
                      <div className="flex-1">
                        <p className="text-sm font-semibold text-slate-800 dark:text-white">{notif.title}</p>
                        <p className="text-xs text-slate-500 mt-1">{notif.message}</p>
                        <p className="text-[10px] text-slate-400 mt-2">{notif.time}</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
              <div className="p-3 border-t border-slate-200 dark:border-slate-800 text-center">
                <button className="text-xs font-bold text-primary hover:underline">Ver todas as notificações</button>
              </div>
            </div>
          )}
        </div>
        <span className="text-sm text-slate-500 capitalize">{currentDate}</span>
      </div>
    </header>
  );
};

export default Header;
